function reverseList(head) {
  let prev = null;
  let current = head;

  while (current) {
    const next = current.next;
    current.next = prev;
    prev = current;
    current = next;
  }

  return prev;
}

public class ListNode
{
    public int val;
    public ListNode next;
    public ListNode(int x = 0, ListNode n = null) { val = x; next = n; }
}

ListNode ReverseList(ListNode head)
{
    ListNode prev = null, cur = head;
    while (cur != null)
    {
        var next = cur.next;
        cur.next = prev;
        prev = cur;
        cur = next;
    }
    return prev;
}

